const float QUBE_W3[64] = {0.144594073f, -0.00365983858f, -0.0203350373f, -0.323383093f, -0.214906693f, 0.219419986f, -0.126897201f, -0.000212879153f, -0.0102152871f, -0.200689957f, -0.231589779f, -0.000129730004f, 0.0803067982f, 0.142176509f, 0.250931561f, -0.000909878523f, 0.00514214439f, 0.261263758f, -0.270244211f, 2.57988759e-05f, 0.00234873616f, -0.00356515381f, -0.202573806f, -0.364405841f, 0.00760454265f, 0.00106845808f, -0.238251165f, 0.0620655864f, 0.0802858397f, -0.0194182955f, -0.105391584f, 0.343654871f, -0.0326407179f, -0.000626232242f, -0.305637002f, -0.257523179f, -0.00111754099f, -0.11701148f, -0.212095007f, 0.145902008f, -0.00117957627f, 0.0684159324f, -0.431621641f, 0.00794402044f, 0.0722599328f, -0.035537824f, -0.23523201f, 0.00173936179f, 0.0364571065f, 0.115159288f, -0.302218854f, 0.198187307f, 0.0347360559f, 0.0189766642f, 0.142148793f, 0.00423847558f, 0.0016950143f, -0.310988039f, -0.00141386327f, -0.197415516f, 0.0593165942f, -0.0536214858f, -0.0678702071f, 0.187737942f};
